import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.owasp.esapi.ESAPI;

@WebServlet("/xss-secure")
public class XSSSecureServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        response.getWriter().println("<html><body>");

        // Sanitize user input using ESAPI library
        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

        response.getWriter().println("User input: " + sanitizedInput);
        response.getWriter().println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
